import { describe, it, expect, beforeEach } from 'vitest';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let service: PreferencesService;

  beforeEach(() => {
    service = new PreferencesService();
  });

  describe('getPreferences', () => {
    it('should return default preferences for unknown user', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return stored preferences for known user', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(false);
    });
  });

  describe('updatePreferences', () => {
    it('should toggle email enabled', () => {
      const prefs = service.updatePreferences('user-1', { email: { enabled: false } });
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update frequency', () => {
      const prefs = service.updatePreferences('user-1', {
        email: { frequency: 'daily-digest' },
      });
      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      const prefs = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation'] },
      });
      expect(prefs.email.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should merge partial updates with existing preferences', () => {
      service.updatePreferences('user-1', {
        email: { frequency: 'weekly-digest' },
      });
      const prefs = service.updatePreferences('user-1', {
        email: { enabled: false },
      });
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('weekly-digest'); // preserved from earlier
    });

    it('should set updatedAt timestamp', () => {
      const before = new Date();
      const prefs = service.updatePreferences('user-1', { email: { enabled: false } });
      expect(prefs.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });

    it('should update SMS preferences independently', () => {
      const prefs = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.email.enabled).toBe(true); // email unchanged
      expect(prefs.webhook.enabled).toBe(true); // webhook unchanged
    });

    it('should update webhook preferences independently', () => {
      const prefs = service.updatePreferences('user-1', {
        webhook: { enabled: false, subscribedCategories: ['welcome'] },
      });
      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toEqual(['welcome']);
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.sms.enabled).toBe(true);
    });

    it('should update multiple channels at once', () => {
      const prefs = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { subscribedCategories: ['order-confirmation'] },
        webhook: { enabled: false },
      });
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(['order-confirmation']);
      expect(prefs.webhook.enabled).toBe(false);
    });

    it('should merge SMS partial updates with existing preferences', () => {
      service.updatePreferences('user-1', {
        sms: { subscribedCategories: ['welcome'] },
      });
      const prefs = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual(['welcome']); // preserved
    });
  });

  describe('resetPreferences', () => {
    it('should restore defaults after reset', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });
      const prefs = service.resetPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.webhook.enabled).toBe(true);
    });

    it('should remove explicit preferences', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      service.resetPreferences('user-1');
      expect(service.hasExplicitPreferences('user-1')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true with default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false for unsubscribed category', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome'] },
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return false for non-immediate frequency', () => {
      service.updatePreferences('user-1', { email: { frequency: 'daily-digest' } });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });
  });

  describe('shouldSend', () => {
    it('should check email channel preferences', () => {
      expect(service.shouldSend('user-1', 'email', 'order-confirmation')).toBe(true);
      service.updatePreferences('user-1', { email: { enabled: false } });
      expect(service.shouldSend('user-1', 'email', 'order-confirmation')).toBe(false);
    });

    it('should check SMS channel preferences', () => {
      expect(service.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(true);
      service.updatePreferences('user-1', { sms: { enabled: false } });
      expect(service.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(false);
    });

    it('should check webhook channel preferences', () => {
      expect(service.shouldSend('user-1', 'webhook', 'order-confirmation')).toBe(true);
      service.updatePreferences('user-1', { webhook: { enabled: false } });
      expect(service.shouldSend('user-1', 'webhook', 'order-confirmation')).toBe(false);
    });

    it('should respect per-channel subscribed categories', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome'] },
        sms: { subscribedCategories: ['order-confirmation'] },
      });
      expect(service.shouldSend('user-1', 'email', 'order-confirmation')).toBe(false);
      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(true);
      expect(service.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(false);
    });

    it('should allow unknown channels by default', () => {
      expect(service.shouldSend('user-1', 'in-app', 'order-confirmation')).toBe(true);
    });

    it('should enforce email frequency for email channel only', () => {
      service.updatePreferences('user-1', { email: { frequency: 'daily-digest' } });
      expect(service.shouldSend('user-1', 'email', 'order-confirmation')).toBe(false);
      // SMS and webhook should not be affected by email frequency
      expect(service.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'webhook', 'order-confirmation')).toBe(true);
    });

    it('should handle channels independently', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { enabled: false },
      });
      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(false);
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(true);
      expect(service.shouldSend('user-1', 'webhook', 'welcome')).toBe(false);
    });
  });

  describe('hasExplicitPreferences', () => {
    it('should return false for unknown user', () => {
      expect(service.hasExplicitPreferences('user-1')).toBe(false);
    });

    it('should return true after update', () => {
      service.updatePreferences('user-1', { email: { enabled: true } });
      expect(service.hasExplicitPreferences('user-1')).toBe(true);
    });
  });

  describe('getAvailableCategories', () => {
    it('should return all notification categories', () => {
      expect(service.getAvailableCategories()).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return a copy, not a reference', () => {
      const cats = service.getAvailableCategories();
      cats.push('order-confirmation');
      expect(service.getAvailableCategories()).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });
  });

  describe('clearAll', () => {
    it('should remove all stored preferences', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      service.updatePreferences('user-2', { email: { enabled: false } });
      service.clearAll();
      expect(service.hasExplicitPreferences('user-1')).toBe(false);
      expect(service.hasExplicitPreferences('user-2')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  const makeUser = (id: string, email: string) => ({
    id,
    name: 'Test User',
    email,
    role: 'member' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  });

  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId,
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: makeUser(userId, email),
    timestamp: new Date(),
  });

  const makeUserCreatedEvent = (userId: string, email: string): UserCreatedEvent => ({
    type: 'user:created',
    user: makeUser(userId, email),
    timestamp: new Date(),
  });

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesService = new PreferencesService();
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
  });

  it('should send notification when preferences allow it', async () => {
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.updatePreferences('user-1', { email: { enabled: false } });
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should suppress notification for unsubscribed category', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { subscribedCategories: ['welcome'] },
    });
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should suppress notification for digest frequency', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { frequency: 'daily-digest' },
    });
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should send to users with default preferences', async () => {
    // user-2 has no explicit preferences — should get defaults (all enabled)
    await eventBus.emit(makeUserCreatedEvent('user-2', 'bob@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should independently handle preferences per user', async () => {
    preferencesService.updatePreferences('user-1', { email: { enabled: false } });
    // user-1 disabled, user-2 default
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    await eventBus.emit(makeOrderCreatedEvent('user-2', 'bob@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(1);
    expect(notificationService.getNotifications()[0]?.recipient).toBe('bob@example.com');
  });

  it('should still send all notifications without preferences service', async () => {
    // Create a fresh service without preferences
    const freshService = new NotificationService(eventBus);
    // The event handlers from the first service are still subscribed,
    // so we use a new event bus
    const freshBus = new EventBus();
    const standaloneService = new NotificationService(freshBus);
    resetNotificationIdCounter();

    await freshBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(standaloneService.getNotifications()).toHaveLength(1);
  });

  it('should suppress SMS notifications when SMS is disabled', async () => {
    preferencesService.updatePreferences('user-1', { sms: { enabled: false } });
    // Email should still work (SMS disabled doesn't affect email)
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should allow disabling email while keeping SMS enabled', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { enabled: false },
      sms: { enabled: true },
    });
    // The current event handlers send via email channel, so should be suppressed
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    expect(notificationService.getNotifications()).toHaveLength(0);
  });
});

